/* eslint-disable no-lone-blocks */

import '../../fonts/Montserrat-SemiBold.otf';

import {
	Box,
	Button,
	Dialog,
	DialogTitle,
	FormHelperText,
	Grid,
	IconButton,
	InputLabel,
	LinearProgress,
	Menu,
	MenuItem,
	Select,
	TextField,
	Typography,
	makeStyles,
	useMediaQuery,
	useTheme,
	Tooltip,
} from '@material-ui/core';
import React, { useEffect, useState } from 'react';
import { generatePath, useHistory } from 'react-router';
import {
	getAprovarContaAction,
	getContasAction,
	getContasExportAction,
	getFinalizarCadastroContaAction,
	getPagamentoPixAction,
	getReaprovarContaAction,
	getReenviarTokenUsuarioAction,
	getTransferenciaP2pAction,
	loadPermissao,
	postAuthMeAction,
	postBlackListSelfieAction,
	postBloquearDeviceAdmAction,
	postDesbloquearDeviceAdmAction,
	postUserBloquearDesbloquearAction,
} from '../../actions/actions';
import { useDispatch, useSelector } from 'react-redux';
import { faQuestionCircle } from '@fortawesome/free-solid-svg-icons';
import CheckIcon from '@material-ui/icons/Check';
import ClearIcon from '@material-ui/icons/Clear';
import CustomButton from '../../components/CustomButton/CustomButton';
import CustomTable from '../../components/CustomTable/CustomTable';
import CustomTextField from '../../components/CustomTextField/CustomTextField';
import DeleteIcon from '@material-ui/icons/Delete';
import { Pagination } from '@material-ui/lab';
import RefreshIcon from '@material-ui/icons/Refresh';
import SettingsIcon from '@material-ui/icons/Settings';
import ViewListIcon from '@material-ui/icons/ViewList';
import { filters_gerenciar_contas } from '../../constants/localStorageStrings';
import { isEqual } from 'lodash';
import { postBloquearDeviceAdm } from '../../services/services';
import { toast } from 'react-toastify';
import useAuth from '../../hooks/useAuth';
import useDebounce from '../../hooks/useDebounce';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCalendar } from '@fortawesome/free-regular-svg-icons';
import moment from 'moment';
import 'moment/locale/pt-br';
import InputMask from 'react-input-mask';
import { APP_CONFIG } from '../../constants/config';
import LoadingScreen from '../../components/LoadingScreen/LoadingScreen';
import {
	faCalendarAlt,
	faTable,
	faTrash,
} from '@fortawesome/free-solid-svg-icons';
import px2vw from '../../utils/px2vw';

const TransacaoP2p = () => {
	const [filters, setFilters] = useState({
		nome: '',
		documento: '',
		cnpj: '',
		email: '',
		id: '',
		status: ' ',
		data_inicial: '',
		data_final: '',
	});

	const [filtersComparation] = useState({
		nome: '',
		documento: '',
		cnpj: '',
		email: '',
		id: '',
		status: ' ',
		data_inicial: '',
		data_final: '',
	});

	const debouncedNome = useDebounce(filters.nome, 800);
	const debouncedId = useDebounce(filters.id, 800);
	const debouncedEmail = useDebounce(filters.email, 800);

	const debouncedNumeroDocumento = useDebounce(filters.documento, 800);
	const debouncedCNPJ = useDebounce(filters.cnpj, 800);

	const [loading, setLoading] = useState(false);
	const token = useAuth();

	const [page, setPage] = useState(1);
	const history = useHistory();
	const dispatch = useDispatch();
	const [permissoes, setPermissoes] = useState([]);
	const theme = useTheme();
	const matches = useMediaQuery(theme.breakpoints.down('md'));

	const useStyles = makeStyles((theme) => ({
		root: {
			display: 'flex',
			flexDirection: 'column',
		},
		headerContainer: {
			display: 'flex',
			flexDirection: 'column',
			justifyContent: 'space-between',
			marginBottom: '25px',
			width: px2vw('100%'),
			'@media (max-width: 1440px)': {
				width: '950px',
			},
			'@media (max-width: 1280px)': {
				width: '850px',
			},
		},
		tableContainer: { marginTop: '1px' },
		pageTitle: {
			color: APP_CONFIG.mainCollors.primary,
			fontFamily: 'Montserrat-SemiBold',
		},
	}));
	const classes = useStyles();
	moment.locale('pt-br');

	useEffect(() => {
		dispatch(
			getTransferenciaP2pAction(
				token,
				debouncedNome,
				debouncedNumeroDocumento,
				debouncedCNPJ,
				debouncedEmail,
				debouncedId,
				filters.status,
				filters.data_inicial,
				filters.data_final,
				page
			)
		);
	}, [
		token,
		debouncedNome,
		debouncedNumeroDocumento,
		debouncedCNPJ,
		debouncedEmail,
		debouncedId,
		filters.status,
		filters.data_inicial,
		filters.data_final,
		page,
	]);

	const columns = [
		{
			headerText: 'Criado em',
			key: 'created_at',
			CustomValue: (data) => {
				const date = new Date(data);
				const option = {
					year: 'numeric',
					month: 'numeric',
					day: 'numeric',
				};
				const formatted = date.toLocaleDateString('pt-br', option);
				return (
					<>
						<Typography align="center"> {formatted}</Typography>
						<Typography align="center">
							{moment.utc(data).format('HH:mm:ss')}
						</Typography>
					</>
				);
			},
		},

		{
			headerText: 'Origem',
			key: 'origem',
			CustomValue: (origem) => {
				const { tipo, documento, nome, razao_social, cnpj, email } = origem;
				return (
					<Box>
						<Typography align="center">
							<b>
								{razao_social === null
									? nome
									: tipo === 'Pessoa Jurídica'
									? razao_social
									: nome}
							</b>
						</Typography>
						<Typography align="center">
							{cnpj === null
								? documento
								: tipo === 'Pessoa Jurídica'
								? cnpj
								: documento}
						</Typography>
						<Typography align="center">{email}</Typography>
					</Box>
				);
			},
		},

		{
			headerText: 'Destino',
			key: 'destino',
			CustomValue: (destino) => {
				const { tipo, documento, nome, razao_social, cnpj, email } =
					destino;
				return (
					<Box>
						<Typography align="center">
							<b>
								{razao_social === null
									? nome
									: tipo === 'Pessoa Jurídica'
									? razao_social
									: nome}
							</b>
						</Typography>
						<Typography align="center">
							{cnpj === null
								? documento
								: tipo === 'Pessoa Jurídica'
								? cnpj
								: documento}
						</Typography>
						<Typography align="center">{email}</Typography>
					</Box>
				);
			},
		},
		{
			headerText: 'Status',
			key: 'status',
			CustomValue: (status) => {
				if (
					status === 'Bem sucedida' ||
					status === 'Sucesso' ||
					status === 'Confirmada' ||
					status === 'Aprovado' ||
					status === 'Criada'
				) {
					return (
						<Typography
							style={{
								color: 'green',
								fontWeight: 'bold',

								borderRadius: '27px',
							}}
						>
							{status}
						</Typography>
					);
				}
				if (status === 'Pendente') {
					return (
						<Typography
							style={{
								color: '#CCCC00',
								fontWeight: 'bold',

								borderRadius: '27px',
							}}
						>
							{status}
						</Typography>
					);
				}
				return (
					<Typography
						style={{
							color: 'red',
							fontWeight: 'bold',

							borderRadius: '27px',
						}}
					>
						{status}
					</Typography>
				);
			},
		},
		{ headerText: 'Tipo', key: 'tipo' },
		{
			headerText: 'Valor',
			key: 'valor',
			CustomValue: (valor) => {
				return (
					<>
						R${' '}
						{parseFloat(valor).toLocaleString('pt-br', {
							minimumFractionDigits: 2,
							maximumFractionDigits: 2,
						})}
					</>
				);
			},
		},
		{
			headerText: 'Id da transação',
			key: 'id',
			CustomValue: (value) => (
				<Typography style={{ lineBreak: 'anywhere' }}>{value}</Typography>
			),
		},
		{
			headerText: 'Descrição',
			key: 'descricao',
			CustomValue: (descricao) => {
				return (
					<Tooltip title={descricao ? descricao : 'Sem descrição'}>
						<Box>
							<FontAwesomeIcon icon={faQuestionCircle} />
						</Box>
					</Tooltip>
				);
			},
		},
		{
			headerText: 'Aprovação',
			key: 'aprovado',
			CustomValue: (value) => {
			  return value === true ? (
				<Tooltip title="Transação Aprovada">
				  <CheckIcon style={{ color: 'green' }} value />
				  </Tooltip>
			  ) : value === false ? (
				<Tooltip title="Transação Não Aprovada">
				  <ClearIcon style={{ color: 'red' }} value />
				  </Tooltip>
			  ) : null;
			},
		  },
	];

	const transferenciaP2p = useSelector((state) => state.transferenciaP2p);
	const me = useSelector((state) => state.me);
	const userPermissao = useSelector((state) => state.userPermissao);

	const handleChangePage = (e, value) => {
		setPage(value);
	};

	useEffect(() => {
		dispatch(postAuthMeAction(token));
	}, []);

	useEffect(() => {
		if (me.id !== undefined) {
			dispatch(loadPermissao(token, me.id));
		}
	}, [me.id]);

	useEffect(() => {
		const { permissao } = userPermissao;
		setPermissoes(permissao.map((item) => item.tipo));
	}, [userPermissao]);

	const Editar = (row) => {
		return <Box></Box>;
	};

	/* useEffect(() => {
		if (!isEqual(filters, filtersComparation)) {
			localStorage.setItem(
				filters_gerenciar_contas,
				JSON.stringify({ ...filters })
			);
		}
	}, [filters]);

	useEffect(() => {
		const getLocalFilters = JSON.parse(
			localStorage.getItem(filters_gerenciar_contas)
		);
		if (getLocalFilters) {
			setFilters(getLocalFilters);
		}
	}, []); */

	return (
		<Box className={classes.root}>
			<LoadingScreen isLoading={loading} />
			<Box className={classes.headerContainer}>
				<Box
					style={{
						marginBottom: '20px',
						display: 'flex',
						justifyContent: 'space-between',
						alignItems: 'center',
					}}
				>
					<Typography className={classes.pageTitle}>
						Transações P2P
					</Typography>
					<Box style={{ alignSelf: 'flex-end' }}>
						<IconButton
							style={{
								backgroundColor: APP_CONFIG.mainCollors.backgrounds,
								color: APP_CONFIG.mainCollors.primary,
							}}
							onClick={() => window.location.reload(false)}
						>
							<RefreshIcon></RefreshIcon>
						</IconButton>
					</Box>
				</Box>
				<Box
					style={{
						width: '100%',
						backgroundColor: APP_CONFIG.mainCollors.backgrounds,
						borderTopLeftRadius: 27,
						borderTopRightRadius: 27,
					}}
				>
					<Box style={{ margin: 30 }}>
						<Grid container spacing={3}>
							<Grid item xs={12} sm={3}>
								<TextField
									fullWidth
									placeholder="Pesquisar por nome ou razão social"
									size="small"
									variant="outlined"
									style={{
										marginRight: '10px',
									}}
									value={filters.nome}
									onChange={(e) => {
										setPage(1);
										setFilters({
											...filters,
											nome: e.target.value,
										});
									}}
								/>
							</Grid>

							<Grid item xs={12} sm={2}>
								<TextField
									variant="outlined"
									InputLabelProps={{ shrink: true }}
									fullWidth
									placeholder="Pesquisar por CPF"
									size="small"
									style={{
										marginRight: '10px',
									}}
									value={filters.documento}
									onChange={(e) => {
										setPage(1);
										setFilters({
											...filters,
											documento: e.target.value,
										});
									}}
								/>
								{/* <InputMask
									maskChar=""
									mask={'999.999.999-99'}
									value={filters.documento}
									onChange={(e) => {
										setPage(1);
										setFilters({
											...filters,
											documento: e.target.value,
										});
									}}
								>
									{() => (
										<TextField
											variant="outlined"
											InputLabelProps={{ shrink: true }}
											fullWidth
											placeholder="Pesquisar por CPF"
											size="small"
											style={{
												marginRight: '10px',
											}}
										/>
									)}
								</InputMask> */}
							</Grid>
							<Grid item xs={12} sm={2}>
								<InputMask
									maskChar=""
									mask={'99.999.999/9999-99'}
									value={filters.cnpj}
									onChange={(e) => {
										setPage(1);
										setFilters({
											...filters,
											cnpj: e.target.value,
										});
									}}
								>
									{() => (
										<TextField
											variant="outlined"
											InputLabelProps={{ shrink: true }}
											fullWidth
											placeholder="Pesquisar por CNPJ"
											size="small"
											style={{
												marginRight: '10px',
											}}
										/>
									)}
								</InputMask>
							</Grid>

							<Grid item xs={12} sm={2}>
								<TextField
									variant="outlined"
									fullWidth
									InputLabelProps={{
										shrink: true,
										pattern: 'd {4}- d {2}- d {2} ',
									}}
									type="date"
									label="Data de criação inicial"
									value={filters.data_inicial}
									onChange={(e) =>
										setFilters({
											...filters,
											data_inicial: e.target.value,
										})
									}
								/>
							</Grid>
							<Grid item xs={12} sm={2}>
								<TextField
									variant="outlined"
									fullWidth
									InputLabelProps={{
										color: APP_CONFIG.mainCollors.secondary,
										shrink: true,
										pattern: 'd {4}- d {2}- d {2} ',
									}}
									type="date"
									label="Data de criação final"
									value={filters.data_final}
									onChange={(e) =>
										setFilters({
											...filters,
											data_final: e.target.value,
										})
									}
								/>
							</Grid>
							<Grid item xs={12} sm={3}>
								<TextField
									fullWidth
									placeholder="Pesquisar por ID"
									size="small"
									variant="outlined"
									style={{
										marginRight: '10px',
									}}
									value={filters.id}
									onChange={(e) => {
										setPage(1);
										setFilters({
											...filters,
											id: e.target.value,
										});
									}}
								/>
							</Grid>
							<Grid item xs={12} sm={3}>
								<TextField
									fullWidth
									placeholder="Pesquisar por E-mail"
									size="small"
									variant="outlined"
									style={{
										marginRight: '10px',
									}}
									value={filters.email}
									onChange={(e) => {
										setPage(1);
										setFilters({
											...filters,
											email: e.target.value,
										});
									}}
								/>
							</Grid>
							<Grid item xs={12} sm={2}>
								<Select
									style={{
										marginTop: '10px',
										color: APP_CONFIG.mainCollors.secondary,
									}}
									variant="outlined"
									fullWidth
									value={filters.status}
									onChange={(e) =>
										setFilters({ ...filters, status: e.target.value })
									}
								>
									<MenuItem
										value={' '}
										style={{
											color: APP_CONFIG.mainCollors.secondary,
										}}
									>
										Status
									</MenuItem>
									<MenuItem
										value={'Registered'}
										style={{
											color: APP_CONFIG.mainCollors.secondary,
										}}
									>
										Pendente
									</MenuItem>
									<MenuItem
										value={'Paid'}
										style={{
											color: APP_CONFIG.mainCollors.secondary,
										}}
									>
										Pago
									</MenuItem>
									<MenuItem
										value={'Cancel'}
										style={{
											color: APP_CONFIG.mainCollors.secondary,
										}}
									>
										Estornado
									</MenuItem>
									<MenuItem
										value={'Error'}
										style={{
											color: APP_CONFIG.mainCollors.secondary,
										}}
									>
										Error
									</MenuItem>
								</Select>
							</Grid>
							<Grid item xs={12} sm={2}>
								<Box
									style={{
										display: 'flex',
										justifyContent: 'flex-end',
										alignItems: 'center',
										height: '100%',
										width: '100%',
									}}
								>
									<CustomButton
										color="red"
										onClick={() => {
											setFilters(filtersComparation);
											localStorage.setItem(
												filters_gerenciar_contas,
												JSON.stringify({ ...filtersComparation })
											);
										}}
									>
										<Box display="flex" alignItems="center">
											<DeleteIcon />
											Limpar
										</Box>
									</CustomButton>
								</Box>
							</Grid>
						</Grid>
					</Box>
				</Box>
				<Box className={classes.tableContainer}>
					{transferenciaP2p.data && transferenciaP2p.per_page ? (
						<Box minWidth={!matches ? '800px' : null}>
							<CustomTable
								columns={columns ? columns : null}
								data={transferenciaP2p.data}
								Editar={Editar}
							/>
						</Box>
					) : (
						<Box>
							<LinearProgress color="secondary" />
						</Box>
					)}
					<Box
						display="flex"
						alignSelf="flex-end"
						marginTop="8px"
						justifyContent="space-between"
					>
						<Pagination
							variant="outlined"
							color="secondary"
							size="large"
							count={transferenciaP2p.last_page}
							onChange={handleChangePage}
							page={page}
						/>
					</Box>
				</Box>
			</Box>
		</Box>
	);
};

export default TransacaoP2p;
